unique, inverse = np.unique(name, return_inverse=True)
count = np.zeros(len(unique), dtype=int)
np.add.at(count, inverse, 1)
name_counts = np.vstack((unique, count)).T
total = name_counts[:, 1].astype(int).sum() - 1
dcounts = dict(zip(name_counts[:, 0], name_counts[:, 1].astype(int) - 1))
sim_matrix = np.zeros((name.shape[0], name.shape[0]))
for i in range(sim_matrix.shape[0]):
    for j in range(sim_matrix.shape[1]):
        if i == j:
            sim_matrix[i, j] = 1
        elif name[i] == name[j]:
            sim_matrix[i, j] = dcounts[name[i]] / total
        else:
            sim_matrix[i, j] = 0
print(f"矩阵形状={sim_matrix.shape}, 小明同名相似度={sim_matrix[0,2]:.2f}")
